import ast; ast.parse("import asyncio\nimport datetime\nimport heapq\nimport logging\nimport uuid\n\nlogger = logging.getLogger(\"task_scheduler\")\nlogger.setLevel(logging.DEBUG)\n_handler = logging.StreamHandler()\n_handler.setFormatter(logging.Formatter(\"[%(asctime)s] %(levelname)-8s %(name)s: %(message)s\"))\nlogger.addHandler(_handler)\nTaskId = str\nPriority = int\nTimestamp = datetime\nTaskResult = Union[(str, int, float, dict, None)]\nTaskCallback = Callable[(..., Awaitable[TaskResult])]\nT = TypeVar(\"T\")\nR = TypeVar(\"R\")\n\n\n@runtime_checkable\nclass Runnable:\n    pass\n\n\n@runtime_checkable\nclass Cancellable:\n    def cancel(self):\n        pass\n\n\nclass TaskState:\n    PENDING = auto()\n    QUEUED = auto()\n    RUNNING = auto()\n    COMPLETED = auto()\n    FAILED = auto()\n    CANCELLED = auto()\n    RETRYING = auto()\n\n\ndef describe_state(state):\n    match state:\n        case TaskState.PENDING:\n            return \"Task is waiting to be queued\"\n        case TaskState.QUEUED:\n            return \"Task is in the priority queue\"\n        case TaskState.RUNNING:\n            return \"Task is currently executing\"\n        case TaskState.COMPLETED:\n            return \"Task finished successfully\"\n        case TaskState.FAILED:\n            return \"Task encountered an error\"\n        case TaskState.CANCELLED:\n            return \"Task was cancelled before completion\"\n        case TaskState.RETRYING:\n            return \"Task is being retried after a failure\"\n        case _:\n            return \"Unknown state\"\n\n\nclass SchedulerError:\n    pass\n\n\nclass TaskNotFoundError:\n    pass\n\n\nclass TaskAlreadyRunningError:\n    pass\n\n\nclass MaxRetriesExceededError:\n    pass\n\n\nclass EventBus:\n    def __init__(self):\n        self._listeners = {}\n\n    def on(self, event, callback):\n        self._listeners.setdefault(event, []).append(callback)\n\n\n@dataclass()\nclass TaskBase:\n    task_id = field(lambda : str(uuid.uuid4()))\n    name = \"unnamed\"\n    priority = 5\n    state = TaskState.PENDING\n    max_retries = 3\n    retry_count = 0\n    created_at = field(lambda : datetime.now(timezone.utc))\n    started_at = None\n    finished_at = None\n    result = None\n    error = None\n    _registry = {}\n\n    def __post_init__(self):\n        TaskBase._registry[self.task_id] = self\n\n    def __lt__(self, other):\n        if notisinstance(other, TaskBase):\n            return NotImplemented\n        return (self.priority, self.created_at) < (other.priority, other.created_at)\n\n    def __eq__(self, other):\n        if notisinstance(other, TaskBase):\n            return NotImplemented\n        return self.task_id == other.task_id\n\n    def __hash__(self):\n        return hash(self.task_id)\n\n    def __repr__(self):\n        return f\"{type(self).__name__}(id={.task_id!r}, name={.name!r}, state={.state.name}, pri={.priority})\"\n\n    def transition(self, new_state):\n        old = self.state\n        match (old, new_state):\n            case [TaskState.CANCELLED, _]:\n                raise SchedulerError(\"Cannot transition from CANCELLED\")\n            case [TaskState.COMPLETED, _]:\n                raise SchedulerError(\"Cannot transition from COMPLETED\")\n            case [_, TaskState.RUNNING]:\n                self.started_at = datetime.now(timezone.utc)\n            case [_, TaskState.COMPLETED | TaskState.FAILED | TaskState.CANCELLED]:\n                self.finished_at = datetime.now(timezone.utc)\n            case _:\n                pass\n        self.state = new_state\n        logger.info(f\"Task {.name!r} {old.name} -> {new_state.name}\")\n\n    def cancel(self):\n        if self.state not in (TaskState.COMPLETED, TaskState.CANCELLED):\n            self.transition(TaskState.CANCELLED)\n\n    @property\n    def elapsed(self):\n        if self.started_at and self.finished_at:\n            return self.finished_at - self.started_at\n        return None\n\n    @abstractmethod\n    async def run(self):\n        pass\n\n    @staticmethod\n    def lookup(self, task_id):\n        if (task := TaskBase._registry.get(task_id) is not None):\n            return task\n        raise TaskNotFoundError(f\"No task with id {task_id!r}\")\n\n\nclass OneShotTask:\n    callback = field(None)\n    args = ()\n    kwargs = field(dict)\n\n    def __init__(self, callback, name=\"\", priority=5, max_retries=3, *args, **kwargs):\n        super().__init__(name or callback.__name__, priority, max_retries)\n        self.callback = callback\n        self.args = args\n        self.kwargs = kwargs\n\n\n@dataclass\nclass PeriodicTask:\n    interval_seconds = 60\n    callback = None\n    _stop_event = field(asyncio.Event, False)\n\n    def stop(self):\n        self._stop_event.set()\n        logger.info(f\"Periodic task {.name!r} stop requested\")\n\n    @property\n    def stopped(self):\n        return self._stop_event.is_set()\n\n\nclass _CompositeBase:\n    children = field(list)\n\n    def child_tasks(self):\n        yield from self.children\n\n    def __add__(self, task):\n        self.children.append(task)\n\n\n@dataclass\nclass CompositeTask:\n    children = field(list)\n\n\n_TASK_FUNCTIONS = {}\n\n\ndef task(func):\n    _TASK_FUNCTIONS[func.__name__] = func\n    logger.debug(f\"Registered task function '{func.__name__}'\")\n    @wraps()\n    async def wrapper(*args, **kwargs):\n        return await func(*args, **kwargs)\n    return wrapper\n\n\ndef scheduled_task(priority=5, max_retries=3):\n    def decorator(func):\n        func._task_priority = priority\n        func._task_max_retries = max_retries\n        _TASK_FUNCTIONS[func.__name__] = func\n        @wraps()\n        async def wrapper(*args, **kwargs):\n            return await func(*args, **kwargs)\n        return wrapper\n    return decorator\n\n\nclass PriorityQueue:\n    def __init__(self):\n        self._heap = []\n        self._entry_set = set()\n\n    def push(self, task):\n        if task.task_id in self._entry_set:\n            return\n        heapq.heappush(self._heap, task)\n        self._entry_set.add(task.task_id)\n        task.transition(TaskState.QUEUED)\n\n    def pop(self):\n        while self._heap:\n            task = heapq.heappop(self._heap)\n            self._entry_set.discard(task.task_id)\n            if task.state != TaskState.CANCELLED:\n                return task\n        raise SchedulerError(\"Priority queue is empty\")\n\n    @property\n    def size(self):\n        return len(self._entry_set)\n\n    def __bool__(self):\n        return self.size > 0\n\n    def __repr__(self):\n        return f\"PriorityQueue(size={.size})\"\n\n    def drain(self):\n        while self:\n            yield self.pop()\n\n\nclass Scheduler:\n    def __init__(self, max_concurrency=4):\n        self._queue = PriorityQueue()\n        self._max_concurrency = max_concurrency\n        self._semaphore = asyncio.Semaphore(max_concurrency)\n        self._events = EventBus()\n        self._running = {}\n        self._shutdown = asyncio.Event()\n\n    def submit(self, task):\n        self._queue.push(task)\n        logger.info(f\"Submitted {task.name!r} (pri={task.priority})\")\n        return task.task_id\n\n    def submit_many(self, *tasks):\n        return [self.submit(t) for t in tasks]\n\n    def shutdown(self):\n        self._shutdown.set()\n        for tid, async_task in self._running.items():\n            async_task.cancel()\n            logger.info(f\"Cancelled in-flight task {tid}\")\n\n    def on_task_started(self, cb):\n        self._events.on(\"task_started\", cb)\n\n    def on_task_completed(self, cb):\n        self._events.on(\"task_completed\", cb)\n\n    def on_task_failed(self, cb):\n        self._events.on(\"task_failed\", cb)\n\n    @asynccontextmanager\n    async def session(self):\n        logger.info(\"Scheduler session starting\")\n        try:\n            yield self\n        finally:\n            self.shutdown()\n            logger.info(\"Scheduler session closed\")\n\n    @property\n    def pending_count(self):\n        return self._queue.size\n\n    @property\n    def running_count(self):\n        return len(self._running)\n\n    def status_report(self):\n        return {\"pending\": self.pending_count, \"running\": self.running_count, \"max_concurrency\": self._max_concurrency, \"shutdown_requested\": self._shutdown.is_set()}\n\n    @asynccontextmanager\n    async def _acquire_slot(self):\n        await self._semaphore.acquire()\n        try:\n            yield\n        finally:\n            self._semaphore.release()\n\n    def __repr__(self):\n        return f\"Scheduler(pending={.pending_count}, running={.running_count}, max_concurrency={._max_concurrency})\"\n\n\nasync def iter_completed(tasks):\n    scheduler = Scheduler()\n    for t in tasks:\n        scheduler.submit(t)\n    await scheduler.process_queue()\n    for t in tasks:\n        if t.state == TaskState.COMPLETED:\n            yield (t.task_id, t.result)\n\n\ndef build_task_chain(callbacks, prefix=\"step\"):\n    children = [OneShotTask(cb, f\"{prefix}_{idx}\", idx) for (idx, cb) in enumerate(callbacks)]\n    composite = CompositeTask(f\"{prefix}_chain\", children)\n    return composite\n\n\n@task\nasync def fetch_data(url=\"https://example.com\"):\n    logger.info(f\"Fetching data from {url}\")\n    await asyncio.sleep(0.01)\n    return {\"url\": url, \"status\": 200}\n\n\n@scheduled_task()\nasync def send_heartbeat():\n    now = datetime.now(timezone.utc)\n    logger.debug(f\"Heartbeat at {now.isoformat()}\")\n    return {\"ts\": now.isoformat()}\n\n\n@task\nasync def aggregate_metrics(*sources, **options):\n    merged = {}\n    for idx, src in enumerate(sources):\n        merged[f\"source_{idx}\"] = src\n    if (fmt := options.get(\"format\") is not None):\n        merged[\"output_format\"] = fmt\n    for key, value in zip(merged.keys(), merged.values()):\n        logger.debug(f\"Metric entry: {key}={value}\")\n    return merged\n"); print("VALID")